What does this program print?

```cpp
#include <iostream>

template <typename T>
void show(T v) { std::cout << "generic: " << v << "\n"; }

template <>
void show<bool>(bool v) {
    std::cout << (v ? "yes" : "no") << "\n";
}

int main() {
    show(42);
    show(true);
    show(3.14);
}
```

