The developer expects `Store<int*>` to store a copy of the pointed-to value, but the value it returns changes after the original variable is modified. What is the bug?

```cpp
#include <iostream>

template <typename T>
class Store {
    T data_;
public:
    explicit Store(T v) : data_{v} {}
    T get() const { return data_; }
};

template <typename T>
class Store<T*> {
    T* ptr_;          // stores the pointer, not a copy
public:
    explicit Store(T* p) : ptr_{p} {}
    T get() const { return *ptr_; }
};

int main() {
    int x = 10;
    Store<int*> s{&x};
    x = 99;
    std::cout << s.get() << "\n";  // developer expects 10, but gets 99
}
```
